def poly(xs: list, x: float):
    res = 0.0
    for coeff in reversed(xs):
        res = res * x + coeff
    return res

def find_zero(xs: list):
    if not xs:
        return 0.0

    eps = 1e-9
    if abs(poly(xs, 0.0)) < eps:
        return 0.0

    v0 = poly(xs, 0.0)
    p = 1.0

    while True:
        vp = poly(xs, p)
        vmp = poly(xs, -p)

        if abs(vp) < eps:
            return p
        if abs(vmp) < eps:
            return -p

        if vmp * v0 < 0:
            lo, hi = -p, 0.0
            val_lo, val_hi = vmp, v0
            break
        elif vp * v0 < 0:
            lo, hi = 0.0, p
            val_lo, val_hi = v0, vp
            break

        p *= 2.0
        if p > 100000000.0:
            return 0.0

    for _ in range(200):
        mid = (lo + hi) / 2.0
        vm = poly(xs, mid)

        if abs(vm) < eps:
            return mid

        if val_lo * vm < 0:
            hi = mid
            val_hi = vm
        else:
            lo = mid
            val_lo = vm

    return mid

