def change_base(x: int, base: int) -> str:
    if x == 0:
        return "0"

    is_negative = x < 0
    if is_negative:
        x = -x

    digits = []
    while x > 0:
        digits.append(str(x % base))
        x //= base

    result = "".join(reversed(digits))
    if is_negative:
        result = "-" + result

    return result

