            if lower_char in ('a', 'e', 'i', 'o', 'u'):
                if 'a' <= char <= 'z':
                    base = ord('a')
                    shifted = chr((ord(char) - base + 2) % 26 + base)
                else:
                    base = ord('A')
                    shifted = chr((ord(char) - base + 2) % 26 + base)
                char = shifted
            char = char.swapcase()
        result.append(char)

