def digits(n):
    if not isinstance(n, int) or isinstance(n, bool):
        raise TypeError("Input must be a true integer type")
    if n <= 0:
        raise ValueError("Input must be a positive integer")

    product = 1
    has_odd = False
    while n > 0:
        digit = n % 10
        if digit % 2 != 0:
            product *= digit
            has_odd = True
        n //= 10

    return product if has_odd else 0

