def find_max(words: List[str]) -> Optional[str]:
    if not words:
        return None

    best_word: Optional[str] = None
    max_unique_count: int = -1

    for word in words:
        current_unique_count: int = len(set(word))

        if current_unique_count > max_unique_count:
            max_unique_count = current_unique_count
            best_word = word
        elif current_unique_count == max_unique_count:
            if word < best_word:
                best_word = word

    return best_word

