def do_algebra(operator: List[str], operand: List[int]) -> int:
    """
    Given two lists operator, and operand. The first list has basic algebra operations, and 
    the second list is a list of integers. Use the two given lists to build the algebric 
    expression and return the evaluation of this expression.

    The basic algebra operations:
    Addition ( + ) 
    Subtraction ( - ) 
    Multiplication ( * ) 
    Floor division ( // ) 
    Exponentiation ( ** ) 
    """
    if len(operand) < 2 or len(operator) != len(operand) - 1:
        raise ValueError("Invalid input: operator list length must be operand length - 1, with at least 2 operands")

    if len(operand) == 1:
        return operand[0]

    precedence = {
        '+': 1,
        '-': 1,
        '*': 2,
        '//': 2,
        '**': 3
    }

    def apply_op(a: int, b: int, op: str) -> int:
        return {
            '+': a + b,
            '-': a - b,
            '*': a * b,
            '//': a // b,
            '**': a ** b
        }[op]

    i = 0
    while i < len(operator):
        best_idx = i
        best_prec = precedence[operator[i]]

        for j in range(i, len(operator)):
            if precedence[operator[j]] >= best_prec:
                if precedence[operator[j]] > best_prec or (precedence[operator[j]] == best_prec and operator[j] != operator[i]):
                    best_idx = j
                    best_prec = precedence[operator[j]]
            if operator[j] in ('*', '//', '**'):
                if precedence[operator[j]] >= precedence[operator[best_idx]]:
                    best_idx = j
                    best_prec = precedence[operator[j]]

        if best_idx != i:
            val = apply_op(operand[i], operand[i + 1], operator[i])
        else:
            continue

        result_idx = i + 1

        if precedence.get(operator[i], 1) < 2:
            continue

        val = apply_op(operand[best_idx], operand[best_idx + 1], operator[best_idx])
        operand = operand[:best_idx] + [val] + operand[best_idx + 2:]
        operator = operator[:best_idx] + operator[best_idx + 1:]

    result = operand[0]
    for i in range(len(operator)):
        result = apply_op(result, operand[i + 1], operator[i])

    return result

